2289	        loop {
2290	            // Have we reached the end of the skip list?
2291	            if self.node.is_null() {
2292	                return None;
2293	            }
2294	
2295	            unsafe {
2296	                // Take the key and value out of the node.
2297	                let key = ptr::read(&(*self.node).key);
2298	                let value = ptr::read(&(*self.node).value);
2299	
2300	                // Get the next node in the skip list.
2301	                //
2302	                // Unprotected loads are okay because this function is the only one currently using
2303	                // the skip list.
2304	                let next = {
2305	                    let node = NodeRef::new(NonNull::new_unchecked(self.node));
2306	                    node.get_level(0)
2307	                        .load(Ordering::Relaxed, epoch::unprotected())
2308	                };
2309	
2310	                // Deallocate the current node and move to the next one.
2311	                Node::dealloc(self.node);
2312	                self.node = next.as_raw() as *mut Node<K, V>;
2313	
2314	                // The current node may be marked. If it is, it's been removed from the skip list
2315	                // and we should just skip it.
2316	                if next.tag() == 0 {
2317	                    return Some((key, value));
2318	                }
2319	            }
2320	        }
2321	    }
