2343	/// Helper function to check if a value is above a lower bound
2344	fn above_lower_bound<V, T, C>(comparator: &C, bound: &Bound<&T>, other: &V) -> bool
2345	where
2346	    T: ?Sized,
2347	    C: Comparator<V, T>,
2348	{
2349	    match *bound {
2350	        Bound::Unbounded => true,
2351	        Bound::Included(key) => comparator.compare(other, key).is_ge(),
2352	        Bound::Excluded(key) => comparator.compare(other, key).is_gt(),
2353	    }
2354	}
