2356	/// Helper function to check if a value is below an upper bound
2357	fn below_upper_bound<V, T, C>(comparator: &C, bound: &Bound<&T>, other: &V) -> bool
2358	where
2359	    T: ?Sized,
2360	    C: Comparator<V, T>,
2361	{
2362	    match *bound {
2363	        Bound::Unbounded => true,
2364	        Bound::Included(key) => comparator.compare(other, key).is_le(),
2365	        Bound::Excluded(key) => comparator.compare(other, key).is_lt(),
2366	    }
2367	}

