            match self.tail {
                Some(ref t) => {
                    let bound = Bound::Excluded(t.key());
                    if below_upper_bound(&self.parent.comparator, &bound, h.key()) {
                        if let Some(e) = mem::replace(&mut self.head, next_head.clone()) {
