            match self.head {
                Some(ref h) => {
                    let bound = Bound::Excluded(h.key());
                    if above_lower_bound(&self.parent.comparator, &bound, t.key()) {
                        if let Some(e) = mem::replace(&mut self.tail, next_tail.clone()) {
                            unsafe {
                                e.node.decrement(guard);
                            }
                        }
                        next_tail
                    } else {
                        unsafe {
                            t.node.decrement(guard);
                        }
                        None
                    }
